import{_ as a,o as d,c as e,a6 as r}from"./chunks/framework.wLlb4ebq.js";const m=JSON.parse('{"title":"Zhihu Adapter","description":"","frontmatter":{},"headers":[],"relativePath":"integrations/zhihu.md","filePath":"integrations/zhihu.md"}'),i={name:"integrations/zhihu.md"};function h(l,t,n,o,c,s){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="zhihu-adapter" tabindex="-1">Zhihu Adapter <a class="header-anchor" href="#zhihu-adapter" aria-label="Permalink to “Zhihu Adapter”">​</a></h1><p>Zhihu adapter 面向知乎文章、专栏和回答内容导出。相比 Linux.do 与 GitHub，知乎页面结构和登录可见性更容易变化，因此需要更明确的 fallback behavior。</p><h2 id="extraction-rules" tabindex="-1">Extraction rules <a class="header-anchor" href="#extraction-rules" aria-label="Permalink to “Extraction rules”">​</a></h2><table tabindex="0"><thead><tr><th>Rule</th><th>Description</th></tr></thead><tbody><tr><td>URL match</td><td>支持 <code>www.zhihu.com</code> 和 <code>zhuanlan.zhihu.com</code></td></tr><tr><td>Page metadata</td><td>抽取标题、作者、来源 URL 和摘要</td></tr><tr><td>Content cleanup</td><td>清理页面噪声，保留正文线索</td></tr><tr><td>Image handling</td><td>复用导入管线的图片策略</td></tr><tr><td>Fallback</td><td>页面结构不匹配时降级为通用网页剪藏</td></tr></tbody></table><h2 id="metadata-fields" tabindex="-1">Metadata fields <a class="header-anchor" href="#metadata-fields" aria-label="Permalink to “Metadata fields”">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Meaning</th></tr></thead><tbody><tr><td>title</td><td>文章、回答或页面标题</td></tr><tr><td>url</td><td>原始 URL</td></tr><tr><td>author</td><td>作者名，可能为空</td></tr><tr><td>excerpt</td><td>页面摘要</td></tr><tr><td>sourceType</td><td>article / answer / web</td></tr><tr><td>tags/category</td><td>规则或 AI 分类</td></tr></tbody></table><h2 id="normalized-schema-mapping" tabindex="-1">normalized schema mapping <a class="header-anchor" href="#normalized-schema-mapping" aria-label="Permalink to “normalized schema mapping”">​</a></h2><table tabindex="0"><thead><tr><th>Source field</th><th>normalizedContent field</th><th>Destination</th></tr></thead><tbody><tr><td>URL</td><td>identity.url</td><td>链接</td></tr><tr><td>page title</td><td>content.title</td><td>标题</td></tr><tr><td>article body / extracted text</td><td>content.body</td><td>Notion blocks / Markdown</td></tr><tr><td>author</td><td>metadata.author</td><td>作者</td></tr><tr><td>source type</td><td>metadata.source</td><td>来源类型</td></tr></tbody></table><h2 id="fallback-behavior" tabindex="-1">fallback behavior <a class="header-anchor" href="#fallback-behavior" aria-label="Permalink to “fallback behavior”">​</a></h2><table tabindex="0"><thead><tr><th>Failure</th><th>fallback behavior</th></tr></thead><tbody><tr><td>页面结构变更</td><td>降级为通用网页剪藏</td></tr><tr><td>登录内容不可见</td><td>只导出可见标题和 URL</td></tr><tr><td>图片不可访问</td><td>改用外链或跳过</td></tr><tr><td>字符串抽取为空</td><td>提示用户当前页面不适合自动导出</td></tr></tbody></table><h2 id="known-limitations" tabindex="-1">Known limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to “Known limitations”">​</a></h2><ul><li>页面结构变化可能导致抽取质量下降。</li><li>登录或权限限制会影响可见内容。</li><li>长文或动态加载内容可能只抽取到部分正文。</li></ul>',12)])])}const u=a(i,[["render",h]]);export{m as __pageData,u as default};
